/*! Lightweight local mermaid renderer fallback (no CDN). */
(function (global) {
  var mermaid = {
    initialize: function () {
      var blocks = document.querySelectorAll('pre code.language-mermaid');
      blocks.forEach(function (code) {
        var pre = code.closest('pre');
        if (!pre) return;
        var wrap = document.createElement('div');
        wrap.className = 'mermaid';
        var escaped = code.textContent
          .replace(/&/g, '&amp;')
          .replace(/</g, '&lt;')
          .replace(/>/g, '&gt;');
        wrap.innerHTML =
          '<svg xmlns="http://www.w3.org/2000/svg" width="100%" height="120" viewBox="0 0 900 120" role="img" aria-label="Mermaid diagram">' +
          '<rect x="1" y="1" width="898" height="118" rx="10" fill="transparent" stroke="currentColor" stroke-opacity="0.3" />' +
          '<foreignObject x="12" y="12" width="876" height="96">' +
          '<div xmlns="http://www.w3.org/1999/xhtml" style="font-family:monospace;font-size:12px;white-space:pre-wrap;line-height:1.25;">' + escaped + '</div>' +
          '</foreignObject></svg>';
        pre.replaceWith(wrap);
      });
    }
  };

  global.mermaid = mermaid;
})(window);
